class EncryptionManager:
    @staticmethod
    def encrypt(data: bytes, provider_name: str) -> bytes:
        # Using our trusty Fernet provider, we'll encrypt the data.
        provider_class = __import__(PROVIDER_REGISTRY[provider_name]).get_provider_class()
        fernet = provider_class(MASTER_KEY)
